#!/bin/bash
sed -i 's/const hasLinescores = (homeCompetitor.linescores && homeCompetitor.linescores.length > 0) || (awayCompetitor.linescores && awayCompetitor.linescores.length > 0);/const hasLinescores = (homeCompetitor.linescores \&\& homeCompetitor.linescores.length > 0) || (awayCompetitor.linescores \&\& awayCompetitor.linescores.length > 0);\n                  let startTime = comp.date ? new Date(comp.date).getTime() : 0;/g' src/services/espnScraper.ts

sed -i 's/} else if (MATCHUP_DELAYED_STATUSES.includes(rawStatus) || descLower.includes('\''suspended'\'') || detailLower.includes('\''suspended'\'') || descLower.includes('\''delayed'\'') || detailLower.includes('\''delayed'\'')) {/} else if (MATCHUP_DELAYED_STATUSES.includes(rawStatus) || descLower.includes('\''suspended'\'') || detailLower.includes('\''suspended'\'') || descLower.includes('\''delayed'\'') || detailLower.includes('\''delayed'\'')) {\n                      if (compState === '\''pre'\'') {\n                          finalStatus = "STATUS_SCHEDULED";\n                          finalStatusDesc = comp.status?.type?.detail || comp.status?.type?.shortDetail || "Delayed";\n                          if (startTime > 0 \&\& Date.now() >= startTime) {\n                              startTime = Date.now() + 30 * 60 * 1000;\n                          }\n                      } else {\n                          finalStatus = "STATUS_DELAYED";\n                      }/g' src/services/espnScraper.ts

sed -i 's/startTime: new Date(comp.date).getTime(),/startTime,/g' src/services/espnScraper.ts

sed -i 's/|| (rawStatus === "STATUS_SCHEDULED" && comp.date && Date.now() >= new Date(comp.date).getTime())) {/|| (rawStatus === "STATUS_SCHEDULED" \&\& startTime > 0 \&\& Date.now() >= startTime)) {/g' src/services/espnScraper.ts
